from dataclasses import dataclass
from typing import List


@dataclass
class HierarchyLevel:
    name: str
    latency_ns: float
    hit_rate: float


@dataclass
class LevelAnalysis:
    name: str
    latency_ns: float
    hit_rate: float
    access_probability: float
    contribution_ns: float


class StorageHierarchy:
    """Multi-level memory/storage hierarchy model."""

    def __init__(self) -> None:
        self._levels: List[HierarchyLevel] = []

    def add_level(
        self, name: str, latency_ns: float, hit_rate: float
    ) -> None:
        self._levels.append(
            HierarchyLevel(name=name, latency_ns=latency_ns, hit_rate=hit_rate)
        )

    def effective_access_time(self) -> float:
        t_eff = 0.0
        miss_prob = 1.0  # Probability of missing all previous levels

        for level in self._levels:
            # Probability this level is accessed AND hits
            access_prob = miss_prob * level.hit_rate
            t_eff += access_prob * level.latency_ns
            miss_prob *= (1.0 - level.hit_rate)

        # If we miss everything, we still must access the last level
        # The last level's hit_rate should be 1.0 (backstop)
        # If it's not, add the remaining probability at the last level's latency
        if miss_prob > 1e-12 and self._levels:
            t_eff += miss_prob * self._levels[-1].latency_ns

        return t_eff

    def analyze(self) -> List[LevelAnalysis]:
        results = []
        miss_prob = 1.0

        for level in self._levels:
            access_prob = miss_prob * level.hit_rate
            contribution = access_prob * level.latency_ns
            results.append(
                LevelAnalysis(
                    name=level.name,
                    latency_ns=level.latency_ns,
                    hit_rate=level.hit_rate,
                    access_probability=access_prob,
                    contribution_ns=contribution,
                )
            )
            miss_prob *= (1.0 - level.hit_rate)

        return results

    def speedup_vs_slowest(self) -> float:
        if not self._levels:
            return 1.0
        slowest = self._levels[-1].latency_ns
        t_eff = self.effective_access_time()
        return slowest / t_eff if t_eff > 0 else float('inf')
